export const searchTemple = (query) => {
  const q = query.toLowerCase();
  const match = Object.values(templesDatabase).find(t => t.name.toLowerCase().includes(q) || t.location.toLowerCase().includes(q));
  return match ? match.id : 'iskcon';
};
